+  // sext (icmp ugt (X & (SMin | (DivC - 1))), SMin)
+  // Also handle the equivalent "eq" pattern when DivC == 2:
+  // sext (icmp eq (X & (SMin | 1)), (SMin | 1))
+  const APInt *MaskC, *CmpC;
   ICmpInst::Predicate Pred;
   if (!match(Add.getOperand(1),
              m_SExt(m_ICmp(Pred, m_And(m_Specific(X), m_APInt(MaskC)),
-                           m_SignMask()))) ||
-      Pred != ICmpInst::ICMP_UGT)
+                           m_APInt(CmpC)))))
     return nullptr;

   APInt SMin = APInt::getSignedMinValue(Add.getType()->getScalarSizeInBits());
-  if (*MaskC != (SMin | (*DivC - 1)))
+  APInt ExpectedMask = SMin | (*DivC - 1);
+  if (*MaskC != ExpectedMask)
+    return nullptr;
+
+  bool IsRounding = false;
+  if (Pred == ICmpInst::ICMP_UGT && *CmpC == SMin)
+    IsRounding = true;
+  else if (Pred == ICmpInst::ICMP_EQ && *CmpC == ExpectedMask && *DivC == 2)
+    IsRounding = true;
+
+  if (!IsRounding)
     return nullptr;

